SELECT v.*, ste.site_nm AS site_nm, cd_vt.code_label AS voucher_type_cd_nm, cd_vs.code_label AS voucher_status_cd_nm FROM pm_voucher v LEFT JOIN sy_site ste ON ste.site_id = v.site_id LEFT JOIN sy_code cd_vt ON cd_vt.code_grp = 'VOUCHER_TYPE' AND cd_vt.code_value = v.voucher_type_cd LEFT JOIN sy_code cd_vs ON cd_vs.code_grp = 'VOUCHER_STATUS' AND cd_vs.code_value = v.voucher_status_cd
ORDER BY v.voucher_id ASC ORDER BY v.voucher_id DESC ORDER BY v.voucher_nm ASC ORDER BY v.voucher_nm DESC ORDER BY v.reg_date ASC ORDER BY v.reg_date DESC ORDER BY v.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

