site_id = #{siteId}, voucher_nm = #{voucherNm}, voucher_type_cd = #{voucherTypeCd}, voucher_value = #{voucherValue}, min_order_amt = #{minOrderAmt}, max_discnt_amt = #{maxDiscntAmt}, expire_month = #{expireMonth}, voucher_status_cd = #{voucherStatusCd}, voucher_status_cd_before = #{voucherStatusCdBefore}, voucher_desc = #{voucherDesc}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE voucher_id = #{voucherId}
